                const slot: u8 = c.n_caps * 2; c.n_caps += 1;
                const open = try c.addNode(.{ .kind = .save, .slot = slot });
                if (try c.parseAlt()) |inner| {
                    c.patchFrag(inner, try c.addNode(.{ .kind = .save, .slot = slot + 1 }));
                    _ = c.expect(')');
